 39→  return icon({ size: 14, className: "shrink-0", style: { color: "#9ca3af" } });
 40→}
 41→
 42→export function UnifiedFeed() {
 43→  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
 44→    projectsApi.list()
 45→  );
 46→
 47→  const { data: feedItems, isLoading } = useSWR(
 48→    projectsData ? "unified-feed" : null,
 49→    async () => {
 50→      if (!projectsData?.data?.length) return [];
 51→
 52→      const projectMap = new Map(
 53→        projectsData.data.map((p) => [p.id, p.name])
 54→      );
 55→      const projectSlice = projectsData.data.slice(0, 10);
 56→
 57→      // Fetch releases, sources, and semantic releases in parallel
 58→      const [releaseResults, sourceResults, srResults] = await Promise.all([
 59→        Promise.all(
 60→          projectSlice.map((p) =>
 61→            releasesApi.listByProject(p.id, 1).catch(() => null)
 62→          )
 63→        ),
 64→        Promise.all(
 65→          projectSlice.map((p) =>
 66→            sourcesApi.listByProject(p.id, 1).catch(() => null)
 67→          )
 68→        ),
 69→        Promise.all(
 70→          projectSlice.map((p) =>
 71→            srApi.list(p.id, 1).catch(() => null)
 72→          )
 73→        ),
 74→      ]);
 75→
 76→      // Build source lookup maps
 77→      const sourceMap = new Map<string, string>();
 78→      const providerMap = new Map<string, string>();
 79→      const sourceProjectMap = new Map<string, string>();
 80→      sourceResults
 81→        .filter((r): r is NonNullable<typeof r> => r !== null)
 82→        .flatMap((r) => r.data)
 83→        .forEach((s: Source) => {
 84→          sourceMap.set(s.id, s.repository);
 85→          providerMap.set(s.id, s.provider);
 86→          sourceProjectMap.set(s.id, s.project_id);
 87→        });
 88→
 89→      // Build feed items
 90→      const items: FeedItemType[] = [];
 91→
 92→      releaseResults
 93→        .filter((r): r is NonNullable<typeof r> => r !== null)
 94→        .flatMap((r) => r.data)
 95→        .forEach((rel) => {
 96→          const projectId = sourceProjectMap.get(rel.source_id);
 97→          items.push({
 98→            kind: "release",
 99→            data: rel,
100→            repository: sourceMap.get(rel.source_id),

100→            repository: sourceMap.get(rel.source_id),
101→            provider: providerMap.get(rel.source_id),
102→            projectName: projectId ? projectMap.get(projectId) : undefined,
103→          });
104→        });
105→
106→      srResults
107→        .filter((r): r is NonNullable<typeof r> => r !== null)
108→        .flatMap((r) => r.data)
109→        .forEach((sr) => {
110→          items.push({
111→            kind: "semantic",
112→            data: sr,
113→            projectName: projectMap.get(sr.project_id),
114→          });
115→        });
116→
117→      // Sort by timestamp descending, take first 15
118→      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
119→      return items.slice(0, 15);
120→    },
121→    { refreshInterval: 30_000 }
122→  );
123→
124→  if (isLoading) {
125→    return (
126→      <div
127→        className="rounded-lg bg-white py-16 text-center"
128→        style={{ border: "1px solid #e8e8e5" }}
129→      >
130→        <p
