138→        </p>
139→      </div>
140→    );
141→  }
142→
143→  if (!feedItems || feedItems.length === 0) {
144→    return null; // Empty state handled by parent
145→  }
146→
147→  return (
148→    <div
149→      className="flex flex-col rounded-lg bg-white"
150→      style={{ border: "1px solid #e8e8e5", height: "336px" }}
151→    >
152→      {/* Header */}
153→      <div
