              {latest.version}
            </Link>
            {latestIcon && latestIcon({ size: 12, className: "shrink-0", style: { color: "#9ca3af" } })}
            {latestSr?.status === "completed" && (
              <Link
                href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
