              >
                <FileText size={10} />
                Report
              </Link>
            )}
            {(latestSr?.status === "pending" || latestSr?.status === "processing") && (
              <span
                className="inline-flex items-center gap-0.5 rounded px-1.5 py-0.5 text-[10px]"
                style={{ backgroundColor: "#fef9c3", color: "#92400e", fontFamily: "var(--font-dm-sans)" }}
