 64→    const firstPage = await projectsApi.list(1, 100);
 65→    return firstPage;
 66→  });
 67→
 68→  /* Fetch releases — scoped by project or all */
 69→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
 70→    projectFilter !== "all" ? ["releases", page, projectFilter, showExcluded] : null,
 71→    () => releasesApi.listByProject(projectFilter, page, PER_PAGE, showExcluded)
 72→  );
 73→
 74→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
 75→    projectFilter === "all" ? ["all-releases", page, showExcluded] : null,
 76→    () => releasesApi.list(page, PER_PAGE, showExcluded)
 77→  );
 78→
 79→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
 80→
 81→  /* Releases come pre-enriched with project/source metadata from the backend */
 82→  const releases: Release[] =
 83→    projectFilter !== "all"
 84→      ? scopedData?.data ?? []
 85→      : allReleasesData?.data ?? [];
 86→
 87→  /* Pagination math */
 88→  const activeData = projectFilter !== "all" ? scopedData : allReleasesData;
 89→  const total = activeData?.meta?.total ?? 0;
 90→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
 91→  const startRow = (page - 1) * PER_PAGE + 1;
 92→  const endRow = Math.min(page * PER_PAGE, total);
 93→
 94→  /* SSE revalidation — refresh on semantic_release events */
 95→  const revalidateReleases = useCallback(() => {
 96→    return mutate((key) => {
 97→      if (Array.isArray(key)) {
 98→        return key[0] === "releases" || key[0] === "all-releases";
 99→      }
100→      return false;
101→    }, undefined, { revalidate: true });
102→  }, []);
103→
104→  useEffect(() => {
105→    let es: EventSource | null = null;
