107→
108→    function connect() {
109→      try {
110→        es = new EventSource(`${SSE_BASE}/events`);
111→        es.onmessage = (event) => {
112→          try {
113→            const parsed = JSON.parse(event.data);
114→            if (parsed.type === "semantic_release") {
115→              setTriggeringVersion(null);
116→              revalidateReleases();
117→            }
118→          } catch {
119→            // ignore parse errors
120→          }
121→        };
122→        es.onerror = () => {
123→          es?.close();
124→          retryTimer = setTimeout(connect, 5000);
125→        };
126→      } catch {
127→        retryTimer = setTimeout(connect, 5000);
128→      }
129→    }
130→
131→    connect();
132→    return () => {
133→      es?.close();
134→      if (retryTimer) clearTimeout(retryTimer);
135→    };
136→  }, [revalidateReleases]);
137→
138→  /* Trigger agent run — keep spinner until SWR revalidation brings back the new status */
139→  const handleTrigger = async (projectId: string, version: string) => {
140→    setTriggeringVersion(version);
141→    try {
142→      await agent.triggerRun(projectId, version);
143→      await revalidateReleases();
144→    } catch {
145→      setTriggeringVersion(null);
146→    }
147→  };
148→
149→  return (
150→    <div className="space-y-6">
151→      {/* Page title */}
152→      <h1
153→        style={{
154→          fontFamily: "var(--font-fraunces)",
155→          fontSize: "24px",
156→          fontWeight: 700,
157→          color: "#111113",
158→        }}
159→      >
160→        Releases
161→      </h1>
162→
163→      {/* Filters */}
164→      <div className="flex items-center gap-3">
165→        <select
166→          value={projectFilter}
167→          onChange={(e) => {
168→            setProjectFilter(e.target.value);
169→            setPage(1);
170→          }}
171→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
172→          style={{
173→            fontFamily: "var(--font-dm-sans)",
174→            fontSize: "13px",
175→            color: "#111113",
176→            border: "1px solid #e8e8e5",
177→          }}
178→          onFocus={(e) =>
179→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
180→          }
181→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
182→        >
183→          <option value="all">All Projects</option>
184→          {projectsData?.data.map((p: Project) => (
185→            <option key={p.id} value={p.id}>
186→              {p.name}
187→            </option>
188→          ))}
189→        </select>
190→
191→        <label className="inline-flex items-center gap-2 cursor-pointer select-none">
192→          <span style={{
193→            fontFamily: "var(--font-dm-sans)",
194→            fontSize: "13px",
195→            color: "#6b7280",
196→          }}>
197→            Show excluded
198→          </span>
