211→            className="relative inline-flex h-5 w-9 items-center rounded-full transition-colors"
212→            style={{ backgroundColor: showExcluded ? "#e8601a" : "#d1d5db" }}
213→          >
214→            <span
215→              className="inline-block h-3.5 w-3.5 rounded-full bg-white transition-transform"
216→              style={{ transform: showExcluded ? "translateX(18px)" : "translateX(3px)" }}
217→            />
218→          </button>
219→        </label>
220→      </div>
221→
222→      {/* Table card */}
223→      <div
224→        className="overflow-hidden rounded-lg bg-white"
225→        style={{ border: "1px solid #e8e8e5" }}
226→      >
227→        {isLoading ? (
228→          <div
229→            className="py-16 text-center"
230→            style={{
231→              fontFamily: "var(--font-dm-sans)",
232→              fontSize: "13px",
233→              color: "#6b7280",
234→            }}
235→          >
236→            Loading...
237→          </div>
238→        ) : releases.length === 0 ? (
239→          <div className="py-16 text-center">
240→            <p
