"use client";

import React, { useState, useMemo, useRef, useEffect, useCallback } from "react";
import useSWR, { mutate } from "swr";
import Link from "next/link";
import { useRouter } from "next/navigation";
import {
  projects as projectsApi,
  releases as releasesApi,
  sources as sourcesApi,
  semanticReleases as srApi,
} from "@/lib/api/client";
import { getProviderIcon } from "@/components/ui/provider-badge";
import { ProjectLogo } from "@/components/ui/project-logo";
import { timeAgo } from "@/lib/format";
import { Plus, ArrowRight, LayoutGrid, List, Search, Pencil, ArrowUpDown, Loader2 } from "lucide-react";
import { SourceForm } from "@/components/sources/source-form";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ProjectForm } from "@/components/projects/project-form";
import type { Project, Source } from "@/lib/api/types";

const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
  critical: { bg: "#dc2626", text: "#ffffff" },
  high: { bg: "#f97316", text: "#ffffff" },
  medium: { bg: "#f59e0b", text: "#ffffff" },
  low: { bg: "#6b7280", text: "#ffffff" },
};

const URGENCY_PILLS: Record<string, { icon: string; bg: string; border: string; text: string }> = {
  critical: { icon: "⚠", bg: "rgba(220,38,38,0.10)", border: "rgba(220,38,38,0.20)", text: "#dc2626" },
  high: { icon: "⚠", bg: "rgba(249,115,22,0.10)", border: "rgba(249,115,22,0.20)", text: "#ea580c" },
  medium: { icon: "●", bg: "rgba(245,158,11,0.10)", border: "rgba(245,158,11,0.20)", text: "#d97706" },
  low: { icon: "✓", bg: "rgba(34,197,94,0.08)", border: "rgba(34,197,94,0.18)", text: "#16a34a" },
};

