            )}
          </>
        ) : (
          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
            {latestSr ? latestSr.status : "No analysis"}
          </span>
        )}
      </span>

      {/* Arrow */}
      <ArrowRight className="h-3.5 w-3.5 shrink-0" style={{ color: "#c4c4c0" }} />
    </div>
  );
