                          color: "#6b7280",
                        }}
                      >
                        {sr.report.summary}
                      </p>
                    )}
                    <p
                      className="mt-1"
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "12px",
                        color: "#9ca3af",
                      }}
